insert into public.questions (topic_id, stem, choices, correct_index, explanation, difficulty)
select t.id, q.stem, jsonb_build_array(q.a, q.b, q.c, q.d), q.correct_index, q.explanation, q.difficulty
from q join t on t.code = q.subject_code and lower(t.name) = lower(q.topic)
where not exists (select 1 from public.questions x where x.stem = q.stem);

-- ===== afar-batch-001 =====
-- Generated from content/afar-batch-001.csv by scripts/csv-to-seed-sql.mjs — do not edit by hand.
-- Idempotent: skips any question whose stem already exists.
with t as (
  select tp.id, tp.name, s.code from public.topics tp
  join public.subjects s on s.id = tp.subject_id
),
q(subject_code, topic, stem, a, b, c, d, correct_index, explanation, difficulty) as (values
  ('AFAR', 'Partnership Accounting',
   'Bea contributes land to a newly formed partnership. She acquired the land for P350,000; its fair value at the contribution date is P500,000, and the partnership assumes the unpaid P100,000 mortgage on it. Bea''s capital account should be credited for:',
   'P250,000', 'P350,000', 'P400,000', 'P500,000',
   2, 'Contributed noncash assets are recorded at fair value net of liabilities assumed by the partnership: P500,000 − P100,000 = P400,000.', 1),
  ('AFAR', 'Partnership Accounting',
   'Dino and Ely form a partnership. Dino contributes cash of P400,000 while Ely contributes equipment with a fair value of P200,000. They agree to have equal capital interests using the bonus method. Ely''s capital credit upon formation is:',
   'P200,000', 'P300,000', 'P400,000', 'P600,000',
   1, 'Total contributed capital is P600,000; equal interests give each partner P300,000. The P100,000 bonus shifts capital from Dino to Ely without recording additional assets.', 2),
  ('AFAR', 'Partnership Accounting',
   'Partners Xander and Yuri share profits as follows: salaries of P200,000 to Xander and P150,000 to Yuri; 10% interest on beginning capitals of P500,000 and P300,000, respectively; any remainder divided 60:40. Net income for the year is P900,000. Xander''s total profit share is:',
   'P368,000', 'P532,000', 'P540,000', 'P580,000',
   1, 'Salaries of P350,000 and interest of P80,000 leave a remainder of P470,000. Xander: P200,000 + P50,000 + (P470,000 × 60%) = P532,000.', 3),
  ('AFAR', 'Partnership Accounting',
   'Mara, the managing partner, is entitled to a bonus of 10% of net income after deducting the bonus. Net income before the bonus is P660,000. The bonus is:',
   'P60,000', 'P66,000', 'P72,600', 'P73,333',
   0, 'Bonus = 10% × (P660,000 − Bonus), so 1.10 Bonus = P66,000 and Bonus = P60,000. Check: 10% × (P660,000 − P60,000) = P60,000.', 2),
  ('AFAR', 'Partnership Accounting',
   'Apol and Ben are entitled to annual salaries of P70,000 and P50,000, respectively, with any remainder shared equally. Salaries are allowed in full even when income is insufficient. Net income for the year is P100,000. Apol''s profit share is:',
   'P40,000', 'P58,333', 'P60,000', 'P70,000',
   2, 'Salaries total P120,000, leaving a negative remainder of P20,000 divided equally. Apol: P70,000 − P10,000 = P60,000.', 2),
  ('AFAR', 'Partnership Accounting',
   'Carla is admitted to a partnership by purchasing one-fourth of Ana''s P400,000 capital interest, paying Ana P150,000 directly. The credit to Carla''s capital account is:',
   'P37,500', 'P100,000', 'P112,500', 'P150,000',
   1, 'A purchase of interest is a personal transaction; the partnership merely transfers one-fourth of Ana''s recorded capital: P400,000 × 1/4 = P100,000. The P150,000 price goes to Ana personally.', 2),
  ('AFAR', 'Partnership Accounting',
   'Old partners Abe (capital P600,000) and Bel (capital P400,000) share profits 3:2. Cid is admitted by investing P500,000 for a 25% interest in the new total capital, with the bonus method applied. The increase in Abe''s capital resulting from Cid''s admission is:',
   'P50,000', 'P62,500', 'P75,000', 'P125,000',
   2, 'Total capital becomes P1,500,000 and Cid is credited 25%, or P375,000, creating a P125,000 bonus to the old partners. Abe receives 3/5 × P125,000 = P75,000.', 2),
  ('AFAR', 'Partnership Accounting',
   'Dana (capital P500,000) and Edna (capital P300,000) share profits equally. Fely invests P200,000 for a 30% interest in the resulting P1,000,000 total capital, with a bonus to the new partner. Dana''s capital balance after Fely''s admission is:',
   'P400,000', 'P437,500', 'P450,000', 'P500,000',
